promise new Promise(resolve => {
    const remoteUrl = window.StudioUIBundleRemoteUrl

    // Check if the container is already available
    if (window['pimcore_studio_ui_bundle']) {
      resolve({
        get: (request) => window['pimcore_studio_ui_bundle'].get(request),
        init: (...arg) => {
          try {
            return window['pimcore_studio_ui_bundle'].init(...arg)
          } catch(e) {
            console.log('remote container already initialized')
          }
        }
      })
      return
    }

    const script = document.createElement('script')
    script.src = remoteUrl
    script.onload = () => {
      const proxy = {
        get: (request) => window['pimcore_studio_ui_bundle'].get(request),
        init: (...arg) => {
          try {
            return window['pimcore_studio_ui_bundle'].init(...arg)
          } catch(e) {
            console.log('remote container already initialized')
          }
        }
      }
      resolve(proxy)
    }
    document.head.appendChild(script);
  })

